arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag,
        // which changes how non-ASCII names are encoded. Our legacy Java consumer
        // expects Shift-JIS filenames, so we explicitly specify the encoding.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, Encoding.GetEncoding("Shift_JIS"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

